}

foreach.example:
int[] nums = {1, 2, 3};
foreach (int n in nums) {
    Console.WriteLine(n);
}

do-while.example:
int n = 0;
do {
    Console.WriteLine(n);
    n++;
} while (n < 3);

switch.example:
switch (day) {
    case 'M':
        Console.WriteLine('Monday');
        break;
    default:
        Console.WriteLine('Other');
}

break.example:
for (int i = 0; i < 10; i++) {
    if (i == 3) break;
    Console.WriteLine(i);
}

continue.example:
for (int i = 0; i < 5; i++) {
    if (i % 2 == 0) continue;
    Console.WriteLine(i);
}

return.example:
int Square(int x) {
    return x * x;
}

try.example:
try {
    int x = 1 / int.Parse('0');
} catch (DivideByZeroException e) {
    Console.WriteLine(e.Message);
}

throw.example:
if (age < 0) {
    throw new ArgumentException('Age cannot be negative');
}

